-- Index unique sur enonce pour éviter les doublons (idempotent)
CREATE UNIQUE INDEX IF NOT EXISTS questions_enonce_unique ON public.questions (enonce);

-- Seed 106 questions complémentaires (39 examen_civique, 21 langue, 22 carte_resident, 24 naturalisation)
-- Sources : livret du citoyen, service-public.gouv.fr, immigration.interieur.gouv.fr
DO $$
DECLARE
  v_civique UUID;
  v_langue UUID;
  v_carte UUID;
  v_nat UUID;
BEGIN
  SELECT id INTO v_civique FROM modules WHERE categorie = 'examen_civique' LIMIT 1;
  SELECT id INTO v_langue FROM modules WHERE categorie = 'langue' LIMIT 1;
  SELECT id INTO v_carte FROM modules WHERE categorie = 'carte_resident' LIMIT 1;
  SELECT id INTO v_nat FROM modules WHERE categorie = 'naturalisation' LIMIT 1;

  IF v_civique IS NULL OR v_langue IS NULL OR v_carte IS NULL OR v_nat IS NULL THEN
    RAISE EXCEPTION 'Un ou plusieurs modules introuvables. Catégories attendues : examen_civique, langue, carte_resident, naturalisation';
  END IF;

  -- EXAMEN CIVIQUE (39)
  ON CONFLICT (enonce) DO NOTHING;

  -- LANGUE (21)
  ON CONFLICT (enonce) DO NOTHING;

  -- CARTE RÉSIDENT (22)
  ON CONFLICT (enonce) DO NOTHING;

  -- NATURALISATION (24)
  ON CONFLICT (enonce) DO NOTHING;
END $$;
